    "markDefs": [],
    "children": [
      {
        "_type": "span",
        "_key": "cp06s0",
        "text": "Daca ai sarit peste vizita de la 1 an — nicio problema, o vad des. Atunci ideal e sa veniti pana in 3 ani. Mai bine mai tarziu decat deloc.",
        "marks": []
      }
    ]
